mapper.select:
SELECT  tja.work_card ,tja.name ,tja.job,tja.credential_grant_date,tja.enabled_time
FROM td_job_grading tjg  join  td_job_authentication tja  on tjg.process = tja.process      and  tjg.certification_job  = tja.job
where  1=1


              and   tja.work_card  =    #{criteria.workCard,jdbcType=VARCHAR}


              and   tja.name  =    #{criteria.name,jdbcType=VARCHAR}


            and    tja.job =    #{criteria.certificationJob,jdbcType=VARCHAR}

            and    tja.enabled_flag  = 1


            and    getdate() < DATEADD(MM,0,tja.enabled_time)



order by tja.credential_grant_date

mapper.update:

update td_job_authentication
set
    enabled_flag    = #{enabledFlag,jdbcType=BIT},
    update_by       = #{updateBy,jdbcType=BIGINT},
    update_time     = #{updateTime,jdbcType=TIMESTAMP}
where id = #{id,jdbcType=BIGINT}
